using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter;

    public StringFormatterTests()
    {
        _formatter = new StringFormatter();
    }

    #region FormatPhoneNumber

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesExpectedFormat()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"\(\d{3}\) \d{3}-\d{4}", result);
    }

    [TestMethod]
    [DataRow("5551234567", "(555) 123-4567")]
    [DataRow("8005551212", "(800) 555-1212")]
    [DataRow("0000000000", "(000) 000-0000")]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber(string input, string expected)
    {
        var result = _formatter.FormatPhoneNumber(input);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string input)
    {
        var ex = Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(input));

        Assert.AreEqual("digits", ex.ParamName);
    }

    #endregion

    #region BuildGreeting

    [TestMethod]
    public void BuildGreeting_WithName_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.Contains("Smith", result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.Contains("Mr.", result);
    }

    [TestMethod]
    [DataRow("Smith", "Dr.", "Dear Dr. Smith,")]
    [DataRow("Jones", "Ms.", "Dear Ms. Jones,")]
    [DataRow("Lee", "Mr.", "Dear Mr. Lee,")]
    public void BuildGreeting_WithTitle_ReturnsFormattedGreeting(string name, string title, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_NullOrWhiteSpace_ThrowsArgumentException(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    #endregion

    #region GenerateSlug

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Blog Post! #1");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_ContainsHyphen()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.Contains("-", result);
    }

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("  Spaces Around  ", "spaces-around")]
    [DataRow("C# Is Great!", "c-is-great")]
    [DataRow("one", "one")]
    public void GenerateSlug_VariousTitles_ReturnsExpectedSlug(string input, string expected)
    {
        var result = _formatter.GenerateSlug(input);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_NullOrWhiteSpace_ThrowsArgumentException(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    #endregion

    #region FormatCurrency

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_EuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_WithCents_MatchesDecimalFormat()
    {
        var result = _formatter.FormatCurrency(42.5m);

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }

    [TestMethod]
    [DataRow("9.99", "$", "$9.99")]
    [DataRow("100", "$", "$100.00")]
    [DataRow("0.5", "€", "€0.50")]
    [DataRow("-10.00", "$", "$-10.00")]
    public void FormatCurrency_VariousAmounts_ReturnsExpectedFormat(
        string amountStr, string symbol, string expected)
    {
        var amount = decimal.Parse(amountStr);

        var result = _formatter.FormatCurrency(amount, symbol);

        Assert.AreEqual(expected, result);
    }

    #endregion
}

